ntent:center;align-items:center;opacity:0;transition:.3s}.modal.active{display:flex;opacity:1}.modal-content{background:#203127;padding:3rem;border-radius:40px;max-width:500px;width:90%;position:relative;transform:scale(.9);transition:.3s;box-shadow:0 30px 60px #00000080;border:1px solid #906946}.modal.active .modal-content{transform:scale(1)}.modal-close{position:absolute;top:20px;right:20px;width:40px;height:40px;border-radius:50%;background:0 0;border:none;font-size:28px;cursor:pointer;color:#bdbdbd;transition:.3s;display:flex;align-items:center;justify-content:center}.modal-close:hover{transform:rotate(90deg);color:#906946;background:#ffffff1a}.toast{position:fixed;bottom:30px;right:30px;background:#203127;color:#bdbdbd;padding:1rem 2rem;border-radius:60px;box-shadow:0 10px 30px #00000080;transform:translateX(400px);transition:.3s;z-index:1001;border:1px solid #906946}.toast.show{transform:translateX(0)}.toast.success{background:#1e4f2e;border-color:#bdbdbd}.toast.error{background:#5e2e2e;border-color:#b66d6d}.text-center{text-align:center}.mt-4{margin-top:2rem}.img-round{border-radius:50%;width:clamp(120px,20vw,200px);height:clamp(120px,20vw,200px);background:#2d3a2f;box-shadow:0 20px 30px -16px #000;margin:0 auto 1.5rem;transition:.5s;animation:float 3s infinite;cursor:pointer}@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-10px)}}.event-img-1{background:url('data:image/svg+xml;utf8,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22 fill=%22%2332543d%22><rect width=%22100%22 height=%22100%22/><text x=%2210%22 y=%2255%22 fill=%22%23906946%22 font-size=%2212%22>Костюм</text></svg>')}.event-img-2{background:url('data:image/svg+xml;utf8,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22 fill=%22%2332543d%22><rect width=%22100%22 height=%22100%22/><text x=%2210%22 y=%2255%22 fill=%22%23906946%22 font-size=%2212%22>Театр</text></svg>')}.event-img-3{background:url('data:image/svg+xml;utf8,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22 fill=%22%2332543d%22><rect width=%22100%22 height=%22100%22/><text x=%2210%22 y=%2255%22 fill=%22%23906946%22 font-size=%2212%22>Бородино</text></svg>')}.article-img-1{background:url('data:image/svg+xml;utf8,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22 fill=%22%2332543d%22><rect width=%22100%22 height=%22100%22/><text x=%2210%22 y=%2255%22 fill=%22%23906946%22 font-size=%2210%22>Сапиосексуалы</text></svg>')}.article-img-2{background:url('data:image/svg+xml;utf8,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22 fill=%22%2332543d%22><rect width=%22100%22 height=%22100%22/><text x=%2210%22 y=%2255%22 fill=%22%23906946%22 font-size=%2210%22>Крысы</text></svg>')}.article-img-3{background:url('data:image/svg+xml;utf8,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22 fill=%22%2332543d%22><rect width=%22100%22 height=%22100%22/><text x=%2210%22 y=%2255%22 fill=%22%23906946%22 font-size=%2210%22>Салоны</text></svg>')}@media (prefers-reduced-motion:reduce){*{animation:none!important;transition:none!important}}
