<nav class="navbar"><div class="container" style="display:flex;justify-content:space-between;align-items:center;width:100%"><a href="#home" class="logo">КК</a><div class="desktop-nav"><a href="#home">Главная</a><a href="#events">Мероприятия</a><a href="#articles">Статьи</a><a href="#online">Онлайн обучение</a><a href="#about">О клубе</a><a href="#contact">Контакты</a></div><div class="burger" id="burger"><span></span><span></span><span></span></div></div></nav>
<div class="mobile-menu" id="mobileMenu"><button class="close-btn" id="closeBtn">×</button><a href="#home">Главная</a><a href="#events">Мероприятия</a><a href="#articles">Статьи</a><a href="#online">Онлайн обучение</a><a href="#about">О клубе</a><a href="#contact">Контакты</a></div><div class="overlay" id="overlay"></div>
<div class="modal" id="articleModal"><div class="modal-content"><button class="modal-close" id="closeModal">×</button><h3 id="modalTitle"></h3><p id="modalContent"></p><button class="btn" id="closeModalBtn">Закрыть</button></div></div>
<div class="modal" id="joinModal"><div class="modal-content"><button class="modal-close" id="closeJoinModal">×</button><h3>Вступление</h3><form id="joinForm"><input type="text" placeholder="Имя" id="joinName" required style="width:100%;margin-bottom:1rem;padding:1rem;background:#1f2f24;border:1px solid #906946;color:#bdbdbd;border-radius:30px"><input type="email" placeholder="Email" id="joinEmail" required style="width:100%;margin-bottom:1rem;padding:1rem;background:#1f2f24;border:1px solid #906946;color:#bdbdbd;border-radius:30px"><textarea placeholder="Почему вы?" rows="3" id="joinReason" style="width:100%;margin-bottom:1rem;padding:1rem;background:#1f2f24;border:1px solid #906946;color:#bdbdbd;border-radius:30px"></textarea><button type="submit" class="btn" style="width:100%">Отправить</button></form></div></div>
<div class="toast" id="toast"></div>

<section class="hero" id="home"><div class="container"><h1>Добро пожаловать в "Крысиный клуб"</h1><p class="lead-text">Пространство для тех, кто инвестирует в личный капитал. Развиваем гибкость мышления через насмотренность.</p><div style="display:flex;gap:1rem;flex-wrap:wrap;margin-top:2rem"><a href="#about" class="btn" id="learnMoreBtn">О клубе</a><a href="#" class="btn btn--outline" id="joinBtn">Вступить</a></div></div></section>

<section class="section" id="benefits"><div class="container"><h2>Практическая польза клуба.</h2><div class="grid-3"><div class="benefit-card"><div class="benefit-icon">💼</div><h3>В бизнесе и переговорах</h3><p>Чтение тренирует фильтрацию данных, развивает речь → высокий чек.</p></div><div class="benefit-card"><div class="benefit-icon">🧠</div><h3>Критическое мышление</h3><p>Дискуссии помогают анализировать и делать выводы.</p></div><div class="benefit-card"><div class="benefit-icon">✨</div><h3>Интеллектуальная харизма</h3><p>Широкий кругозор = лидер мнений.</p></div><div class="benefit-card"><div class="benefit-icon">🎨</div><h3>Насмотренность</h3><p>Визуальный опыт рождает оригинальные идеи.</p></div></div></div></section>

<section class="section" id="events"><div class="container"><h2>Ближайшие события.</h2><div class="events-grid articles-grid"><div class="event-card article-card"><div class="article-img event-img-1"></div><div class="meta">Экскурсия</div><h4>Что общего между русским костюмом и Индией?</h4><p>Двойная экскурсия + фотосессия в Царицыно.</p><a href="#" class="read-link event-link">Подробнее</a></div><div class="event-card article-card"><div class="article-img event-img-2"></div><div class="meta">Экскурсия</div><h4>Экскурсия в Большой театр</h4><p>Лекция по истории театра + фотосессия.</p><a href="#" class="read-link event-link">Подробнее</a></div><div class="event-card article-card"><div class="article-img event-img-3"></div><div class="meta">Поездка</div><h4>Поездка в Бородино</h4><p>С историком Павлом Алехиным.</p><a href="#" class="read-link event-link">Подробнее</a></div></div></div></section>

<section class="section" id="articles"><div class="container"><h2>Полезные статьи.</h2><div class="articles-grid"><article class="article-card" data-article="1"><div class="article-img article-img-1"></div><div class="meta">15 мар · 8 мин</div><h4>Сапиосексуалы. Почему немодно быть безграмотным?</h4><a href="#" class="read-link article-link">Читать</a></article><article class="article-card" data-article="2"><div class="article-img article-img-2"></div><div class="meta">10 мар · 6 мин</div><h4>Истории "поедания" книг крысами</h4><a href="#" class="read-link article-link">Читать</a></article><article class="article-card new-article" data-article="3"><div class="article-img article-img-3"></div><div class="meta">5 мар · 10 мин</div><h4>История интеллектуальных клубов</h4><a href="#" class="read-link article-link">Читать</a></article></div><div class="text-center mt-4"><a href="#" class="btn" id="allArticlesBtn">Все статьи →</a></div></div></section>

<section class="section" id="online"><div class="container"><h2>Онлайн обучение</h2><p class="lead-text">Скоро появятся курсы от экспертов.</p><div style="height:100px"></div></div></section>

<section class="section" id="about"><div class="container"><div class="about-block about-grid"><div class="about-text"><h2 style="color:#1f2a36;border-bottom-color:#906946">О клубе</h2><p style="color:#1f2a36">Основатель — Кристина Егорова, экс-продюсер Kion, ведущая «Деконструкции». Опыт съёмок от Владивостока до Узбекистана.</p></div><div class="about-image" style="background-image:url('data:image/svg+xml;utf8,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22 fill=%22%2332543d%22><rect width=%22100%22 height=%22100%22/><text x=%2210%22 y=%2255%22 fill=%22%23906946%22 font-size=%2212%22>Кристина</text></svg>')"></div></div></div></section>

<section class="section" id="resources"><div class="container"><h2>Полезные материалы</h2><div class="grid-3"><ul class="resource-list"><li onclick="showToast('Философский словарь')">Философский словарь</li><li onclick="showToast('Эссе о бюрократии')">Эссе о бюрократии</li><li onclick="showToast('Архив дискуссий')">Архив дискуссий</li></ul><ul class="resource-list"><li onclick="showToast('Лекции по литературе')">Лекции по литературе</li><li onclick="showToast('Критические статьи')">Критические статьи</li><li onclick="showToast('Интервью')">Интервью</li></ul><ul class="resource-list"><li onclick="showToast('Календарь событий')">Календарь событий</li><li onclick="showToast('Библиотека PDF')">Библиотека PDF</li><li onclick="showToast('Подкасты')">Подкасты</li></ul></div></div></section>

<div class="container"><div class="accent-block" id="accentBlock"><p>Присоединяйтесь</p><h3>Крысиному клубу</h3><p>Эксклюзивные материалы и встречи</p><a href="#" class="btn btn--outline" id="joinFromAccent" style="margin-top:1rem">Стать членом</a></div></div>

<section class="section" id="contact"><div class="container"><h2>Контакты</h2><div class="contact-grid"><div><div class="contact-item" onclick="copyToClipboard('club@krysy.ru')"><strong>Email</strong><span>club@krysy.ru</span></div><div class="contact-item" onclick="copyToClipboard('8 800 123-45-67')"><strong>Телефон</strong><span>8 800 123-45-67</span></div><div class="contact-item" onclick="showToast('Москва, Пушкинская 10')"><strong>Адрес</strong><span>ул. Пушкинская, 10</span></div><div class="img-round" id="contactImage"></div></div><div class="contact-form"><h3 style="margin-bottom:1.5rem">Напишите нам</h3><input type="text" placeholder="Имя" id="contactName"><input type="email" placeholder="Email" id="contactEmail"><textarea placeholder="Сообщение" id="contactMessage"></textarea><button class="btn" id="sendMessageBtn">Отправить</button></div></div></div></section>

<footer class="footer"><div class="container" style="display:flex;justify-content:space-between;align-items:center;width:100%;flex-wrap:wrap"><div>© Крысиная канцелярия, 2026</div><div style="display:flex;gap:2rem;flex-wrap:wrap"><a href="#" onclick="showToast('Политика')">Политика</a><a href="#" onclick="showToast('Условия')">Условия</a></div></div></footer>

<script>
const burger=document.getElementById('burger'),mobileMenu=document.getElementById('mobileMenu'),overlay=document.getElementById('overlay'),closeBtn=document.getElementById('closeBtn'),body=document.body;
function openMenu(){burger.classList.add('open');mobileMenu.classList.add('active');overlay.classList.add('active');body.classList.add('menu-open')}
function closeMenu(){burger.classList.remove('open');mobileMenu.classList.remove('active');overlay.classList.remove('active');body.classList.remove('menu-open')}
burger?.addEventListener('click',openMenu);closeBtn?.addEventListener('click',closeMenu);overlay?.addEventListener('click',closeMenu);
document.querySelectorAll('.mobile-nav-link, .nav-link, #homeLink, #learnMoreBtn').forEach(l=>l.addEventListener('click',(e)=>{const h=l.getAttribute('href');if(h?.startsWith('#')){e.preventDefault();if(l.classList.contains('mobile-nav-link'))closeMenu();setTimeout(()=>document.getElementById(h.substring(1))?.scrollIntoView({behavior:'smooth'}),100)}}));
const articleModal=document.getElementById('articleModal'),joinModal=document.getElementById('joinModal'),modalTitle=document.getElementById('modalTitle'),modalContent=document.getElementById('modalContent');
const arts={1:{title:'Сапиосексуалы',content:'Интеллект как новая валюта. В мире ценится критическое мышление.'},2:{title:'Крысы и книги',content:'Как грызуны уничтожали фолианты в библиотеках Европы.'},3:{title:'История клубов',content:'От симпосиев до салонов — место рождения идей.'}};
function openArticleModal(id){if(arts[id]){modalTitle.innerText=arts[id].title;modalContent.innerText=arts[id].content;articleModal.classList.add('active');body.style.overflow='hidden'}}
function closeModal(m){m.classList.remove('active');body.style.overflow=''}
document.querySelectorAll('.article-link').forEach(l=>l.addEventListener('click',(e)=>{e.preventDefault();openArticleModal(l.dataset.article)}));
document.querySelectorAll('.event-link').forEach(l=>l.addEventListener('click',(e)=>{e.preventDefault();showToast('Инфо появится скоро')}));
document.getElementById('closeModal')?.addEventListener('click',()=>closeModal(articleModal));
document.getElementById('closeModalBtn')?.addEventListener('click',()=>closeModal(articleModal));
document.getElementById('closeJoinModal')?.addEventListener('click',()=>closeModal(joinModal));
articleModal.addEventListener('click',(e)=>{if(e.target===articleModal)closeModal(articleModal)});
joinModal.addEventListener('click',(e)=>{if(e.target===joinModal)closeModal(joinModal)});
document.getElementById('joinBtn')?.addEventListener('click',(e)=>{e.preventDefault();joinModal.classList.add('active');body.style.overflow='hidden'});
document.getElementById('joinFromAccent')?.addEventListener('click',(e)=>{e.preventDefault();joinModal.classList.add('active');body.style.overflow='hidden'});
document.getElementById('joinForm')?.addEventListener('submit',(e)=>{e.preventDefault();const nm=document.getElementById('joinName')?.value;showToast(nm?`Спасибо, ${nm}!`:'Заполните поля',nm?'success':'error');closeModal(joinModal)});
const toast=document.getElementById('toast');let tm;
window.showToast=(msg,type='info')=>{clearTimeout(tm);toast.textContent=msg;toast.className='toast show '+(type==='success'?'success':type==='error'?'error':'');tm=setTimeout(()=>toast.classList.remove('show'),3000)};
window.copyToClipboard=t=>{navigator.clipboard?.writeText(t).then(()=>showToast('Скопировано','success')).catch(()=>showToast('Ошибка','error'))};
document.getElementById('sendMessageBtn')?.addEventListener('click',(e)=>{e.preventDefault();showToast(document.getElementById('contactName')?.value?'Отправлено!':'Заполните поля')});
document.querySelectorAll('.benefit-card').forEach(c=>c.addEventListener('mousemove',function(e){const r=this.getBoundingClientRect();this.style.setProperty('--x',((e.clientX-r.left)/r.width*100)+'%');this.style.setProperty('--y',((e.clientY-r.top)/r.height*100)+'%')}));
document.getElementById('contactImage')?.addEventListener('click',()=>showToast('Наше сообщество'));
document.getElementById('allArticlesBtn')?.addEventListener('click',(e)=>{e.preventDefault();showToast('Статьи после регистрации')});
</script>
</body></html>
